import React from 'react';
import { GitHubCalendar } from 'react-github-calendar';
import { motion } from 'framer-motion';
import { useInView } from 'react-intersection-observer';
import '../css/GitHubActivity.css';

const darkTheme = {
  level0: '#1e293b',
  level1: '#14532d',
  level2: '#166534',
  level3: '#15803d',
  level4: '#059669',
};

const lightTheme = {
  level0: '#e2e8f0',
  level1: '#bbf7d0',
  level2: '#4ade80',
  level3: '#16a34a',
  level4: '#15803d',
};

const GitHubActivity = ({ isDark }) => {
  const [ref, inView] = useInView({ triggerOnce: true, threshold: 0.1 });

  const containerVariants = {
    hidden: { opacity: 0, y: 30 },
    visible: { opacity: 1, y: 0, transition: { duration: 0.6, ease: 'easeOut' } },
  };

  return (
    <motion.section
      className="github-activity"
      id="github-activity"
      ref={ref}
      variants={containerVariants}
      initial="hidden"
      animate={inView ? 'visible' : 'hidden'}
    >
      <div className="container">
        <div className="github-section-header">
          <h1 className="github-section-title">GitHub Activity</h1>
          <p className="github-section-subtitle">
            Open-source contributions over the past year
          </p>
        </div>

        <div className="github-calendar-wrapper">
          <GitHubCalendar
            username="camilolaiton"
            theme={isDark ? darkTheme : lightTheme}
            colorScheme={isDark ? 'dark' : 'light'}
            blockSize={14}
            blockMargin={4}
            fontSize={14}
          />
        </div>

        <div className="github-cta">
          <a
            href="https://github.com/camilolaiton"
            target="_blank"
            rel="noopener noreferrer"
            className="github-cta__btn"
          >
            View GitHub Profile →
          </a>
        </div>
      </div>
    </motion.section>
  );
};

export default GitHubActivity;
