import React, { useState, useEffect } from 'react';
import 'bootstrap/dist/css/bootstrap.min.css';
import './index.css';
import Header from './components/Header';
import About from './components/About';
import Projects from './components/Projects';
import WorkExperience from './components/WorkExperience';
import Publications from './components/Publications';
import BlogPosts from './components/BlogPosts';
import GitHubActivity from './components/GitHubActivity';
import Skills from './components/Skills';
import Footer from './components/Footer';
import Navigation from './components/Navigation';

const App = () => {
  const [sharedData, setSharedData] = useState({});
  const [loading, setLoading] = useState(true);
  const [theme, setTheme] = useState('dark');

  const toggleTheme = () => {
    const newTheme = theme === 'light' ? 'dark' : 'light';
    setTheme(newTheme);
    document.body.setAttribute('data-theme', newTheme);
  };

  const loadProfileData = async () => {
    try {
      const response = await fetch(`${process.env.PUBLIC_URL}/personal_information.json`);
      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }
      const data = await response.json();
      setSharedData(data);
      document.title = data.name || 'Camilo Laiton Portfolio';
      setLoading(false);
    } catch (error) {
      console.error('Error loading profile data:', error);
      setLoading(false);
    }
  };

  useEffect(() => {
    loadProfileData();
    document.body.setAttribute('data-theme', 'dark');
  }, []);

  if (loading) {
    return (
      <div className="loading-container" style={{
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        minHeight: '100vh',
        background: 'var(--gradient-hero)',
        color: 'var(--color-text-on-dark)',
        fontSize: 'var(--font-size-lg)',
        fontWeight: 'var(--font-weight-medium)'
      }}>
        Loading portfolio...
      </div>
    );
  }

  return (
    <div className="App">
      <Navigation />

      <Header
        name={sharedData.name}
        socialInfo={sharedData.social}
        theme={theme}
        toggleTheme={toggleTheme}
      />

      <About
        languages={sharedData.speakLanguages}
      />

      <Projects />

      <WorkExperience
        workInfo={sharedData.projects}
      />

      <Publications
        researchInfo={sharedData.research}
      />

      <BlogPosts />

      <GitHubActivity isDark={theme === 'dark'} />

      <Skills
        sharedSkills={sharedData.skills}
        resumeBasicInfo={sharedData.name}
      />

      <About
        honors={sharedData.honors}
        certificates={sharedData.certificates}
        showAbout={false}
        showHonors={true}
        showCertificates={false}
      />

      <Footer
        socialInfo={sharedData.social}
        name={sharedData.name}
      />
    </div>
  );
};

export default App;
